#include <gtest/gtest.h>
#include <solvers/singleDigit.h>

TEST(TestTurbot, SkyCraper1) {
    // Skyscraper: 6 in r7c2,r9c7 (connected by r6c27) => r7c9,r9c1<>6
    Inst inst = {0x50, 0x51, 0x56, 0x61, 0x86, 5,  // conditions
                 0x68, 0x05, 0x80, 0x05};          // conluctions
    std::vector<uint16_t> executees = {0x6805, 0x8005};
    Grid grid(
        "1100000000000000000010100000001010101600000000000000101001000000000011"
        "0014000000000012000000000000001000001000000101000018000000000000000011"
        "1010120000000000000010100000000001001000010000000000000000110010000010"
        "0100100001010100000300000000000001001100001900000000000010001000000010"
        "0100000008000000000000000011000017000000000003000000000011000000000000"
        "0001000010150000000000060000000000000000000110170000000000000001000110"
        "1200000000001700000000000200000000000000000100100010000001001400000000"
        "0000100000011003000000000000000001011015000000000015000000000000000101"
        "0010180000000000070000000000020000000000130000000000000000010010110000"
        "0000000000010100101900000000000000000110000010010100000300000000000010"
        "0000110015000000000002000000000000000100100000000001010000010000010000"
        "0001001000001100001000001000000100001000001110160000000000050000000000"
        "1300000000000000010001100000000101001500000000001300000000000400000000"
        "00000000001110120000000000000000010010000000011010110000000000");
    findTurbotFish(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

